module top_module(din, clk_inv, rst_l, load, q);parameter SIZE = 1;

  input   [SIZE-1:0]      din ;   // data in
  input                   clk_inv ;   // clk_inv or scan clk_inv
  input                   rst_l ;   // reset
  input                   load ;   // load

  output  [SIZE-1:0]      q ;     // output

  reg [SIZE-1:0] q;
  always @ (posedge clk_inv or negedge rst_l)
    if (~rst_l) begin
      q <= {SIZE{1'b0}};
    end else if (load) begin
      q <= din;
    end else begin
      q <= q;
    end

endmodule
